#include <stdio.h>
#include <string.h>
#define MAX 100005
int main() {
    char s[MAX];
    int q, x, minLength, maxLength, L, R;
    scanf("%s", s);
    scanf("%d", &q);
    while (q--) {
        scanf("%d %d %d %d %d", &x, &minLength, &maxLength, &L, &R);
        int start = -1, end = -1;
        for (int i = L; i <= R; i++) {
            int freq[26] = {0};
            int unique = 0;
            for (int j = i; j <= R; j++) {
                if (freq[s[j] - 'a'] == 0) unique++;
                freq[s[j] - 'a']++;
                if (unique == x && j - i + 1 >= minLength && j - i + 1 <= maxLength) {
                    start = i;
                    end = j;
                    break;
                }
            }
            if (start != -1) break;
        }
        printf("%d %d\n", start, end);
    }
    return 0;
}

