                    if (freq[s.charAt(j) - 'a'] == 0) unique++;
                    freq[s.charAt(j) - 'a']++;
                    if (unique == x && j - i + 1 >= minLength && j - i + 1 <= maxLength) {
                        start = i;
                        end = j;
