def solve(s, x, minLength, maxLength, L, R):
    for i in range(L, R + 1):
        freq = [0] * 26
        unique = 0
        for j in range(i, R + 1):
            if freq[ord(s[j]) - ord('a')] == 0: unique += 1
            freq[ord(s[j]) - ord('a')] += 1
            if unique == x and j - i + 1 >= minLength and j - i + 1 <= maxLength:
                return i, j
    return -1, -1

t = int(input())
s = input()
for _ in range(t):
    x, minLength, maxLength, L, R = map(int, input().split())
    start, end = solve(s, x, minLength, maxLength, L, R)
    print(start, end)

